const PB_URL=($('Config').first().json.pbUrl||'').replace(/\/+$/,'');
const token=$('PB Auth').first().json.token; const pbH={Authorization:token};
const body=($('Webhook').first().json.body)||{};
const ids=Array.isArray(body.ids)?new Set(body.ids):null;
const NONLATIN=/[\u0370-\u03FF\u0400-\u052F\u0530-\u058F\u0590-\u05FF\u0600-\u06FF\u0700-\u07FF\u0900-\u097F\u0E00-\u0E7F\u1100-\u11FF\u3040-\u30FF\u3400-\u9FFF\uAC00-\uD7AF\uF900-\uFAFF]/;
const need=[]; let page=1;
while(true){
  const r=await this.helpers.httpRequest({method:'GET',url:PB_URL+'/api/collections/clubs/records',qs:{filter:'name_en=""',perPage:500,page,fields:'id,name,name_en'},headers:pbH,json:true});
  for(const c of (r.items||[])){ if(ids&&!ids.has(c.id))continue; if(c.name&&NONLATIN.test(c.name)) need.push({id:c.id,name:c.name}); }
  if(page>=(r.totalPages||1))break; page++;
}
const out=[]; for(let i=0;i<need.length;i+=50){ out.push({json:{batch:need.slice(i,i+50)}}); }
if(!out.length) return [{json:{batch:[],empty:true}}];
return out;

const PB_URL=($('Config').first().json.pbUrl||'').replace(/\/+$/,'');
const token=$('PB Auth').first().json.token; const pbH={Authorization:token};
const batch=(($('Loop').item)||{}).json && $('Loop').item.json.batch || [];
let out=$json.output; if(out&&typeof out!=='string'&&out.text)out=out.text; out=String(out||'');
let arr=[];
try{arr=JSON.parse(out);}catch(e){const m=out.match(/\[[\s\S]*\]/); if(m){try{arr=JSON.parse(m[0]);}catch(_){ arr=[]; }}}
if(!Array.isArray(arr)) arr=[];
let written=0;
for(const r of arr){ const idx=(r&&typeof r.i==='number')?r.i:-1; const item=batch[idx]; if(!item)continue; const ne=String((r&&r.name_en)||'').trim(); if(!ne||ne===item.name)continue; try{await this.helpers.httpRequest({method:'PATCH',url:PB_URL+'/api/collections/clubs/records/'+item.id,headers:pbH,body:{name_en:ne},json:true});written++;}catch(e){} }
return [{json:{batchSize:batch.length,written}}];
